args.query:
SELECT Symbol, "Company Description" AS company_name
FROM stockinfo
WHERE "Listing Exchange" = 'Q' AND "Market Category" = 'S' AND (ETF IS NULL OR ETF <> 'Y') AND "Test Issue" <> 'Y';

